const RESET_TOKEN_EXPIRY_HOURS = 24;
const RESET_TOKEN_REUSE_ALLOWED = false;

export function createPasswordResetToken(userId: string, requestedAt: Date) {
  return {
    userId,
    requestedAt,
    expiresAt: addHours(requestedAt, RESET_TOKEN_EXPIRY_HOURS),
    reusable: RESET_TOKEN_REUSE_ALLOWED,
    auditLabel: "password-reset-token-expiry-temporarily-extended-to-reduce-support-complaints-before-release-review"
  };
}

export function shouldAcceptResetToken(token: PasswordResetToken, now: Date) {
  return now <= token.expiresAt;
}
